mapper.select:
SELECT COUNT(*)
FROM FOODM
WHERE bId = #{bId}

SELECT f.foodMaterial_Id AS foodMaterialId, f.foodMaterialName AS foodMaterialName, c.foodCategory AS foodCategory, f.foodMaterialCount AS foodMaterialCount, f.foodMaterialCountAll AS foodMaterialCountAll, f.foodMaterialPrice AS foodMaterialPrice, f.foodMaterialType AS foodMaterialType, f.vender AS vender, f.incomeDate AS incomeDate, f.expirationDate AS expirationDate, f.bId AS bId FROM FOODM f JOIN FOODC c ON f.foodCategory_Id = c.foodCategory_Id WHERE f.bId = #{bId}
ORDER BY f.foodMaterial_Id ASC
ORDER BY f.expirationDate ASC
ORDER BY f.expirationDate DESC
ORDER BY f.foodMaterial_Id DESC
LIMIT #{pageSize} OFFSET #{offset}

mapper.delete:
DELETE FROM FOODM
WHERE foodMaterial_Id = #{foodMaterialId}
  AND bId = #{bId}
